import type { FC } from 'react';
import React from 'react';

import { PANELS } from '../../constants';
import { CalendarDayView } from '../../views/CalendarDayView';
import { CalendarMonthView } from '../../views/CalendarMonthView';
import { CalendarYearView } from '../../views/CalendarYearView';
import type { CalendarPanelProps } from './CalendarPanel.types';

export const CalendarPanel: FC<CalendarPanelProps> = ({
	panel,
	minDate,
	maxDate,
	viewDate,
	disabledStartDate,
	disabledEndDate,
	selectedDate, // одиночная или массив
	selectDay,
	multiselect,
	readonly,
	excludeDate,
	holidaysDate,
	setDaysPanel,
	setMonthsPanel,
	selectMonth,
	selectYear,
	timeZone,
	customizeDay,
	showAdjacentMonthDays,
	allowAdjacentMonthSelection,
}) => {
	switch (panel) {
		case PANELS.DAYS: {
			return (
				<CalendarDayView
					minDate={minDate}
					maxDate={maxDate}
					viewDate={viewDate}
					disabledStartDate={disabledStartDate}
					disabledEndDate={disabledEndDate}
					selectedDate={selectedDate}
					onSelectDay={selectDay}
					multiselect={multiselect}
					readonly={readonly}
					excludeDate={excludeDate}
					holidaysDate={holidaysDate}
					customizeDay={customizeDay}
					timeZone={timeZone}
					showAdjacentMonthDays={showAdjacentMonthDays}
					allowAdjacentMonthSelection={allowAdjacentMonthSelection}
				/>
			);
		}
		case PANELS.MONTHS: {
			return (
				<CalendarMonthView
					minDate={minDate}
					maxDate={maxDate}
					viewDate={viewDate}
					showStartPanel={setDaysPanel}
					onSelectMonth={selectMonth}
					timeZone={timeZone}
				/>
			);
		}
		case PANELS.YEARS: {
			return (
				<CalendarYearView
					viewDate={viewDate}
					selectedYear={viewDate.getFullYear()}
					minYear={minDate?.getFullYear()}
					maxYear={maxDate?.getFullYear()}
					onSelectYear={selectYear}
					showStartPanel={setMonthsPanel}
					timeZone={timeZone}
				/>
			);
		}
		default: {
			return null;
		}
	}
};
